import torch
import torch.nn as nn
import math
from torch.utils.cpp_extension import load_inline

# Define the fused CUDA kernel
fused_conv_transpose_pool_source = """
#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>

template<typename T>
__global__ void fused_conv_transpose_pool_kernel(
    const T* input,
    const T* weight,
    const T* bias,
    T* output,
    const int batch_size,
    const int in_channels,
    const int out_channels,
    const int in_height,
    const int in_width,
    const int out_height,
    const int out_width,
    const int kernel_h,
    const int kernel_w,
    const int stride_h,
    const int stride_w,
    const int padding_h,
    const int padding_w,
    const int output_padding_h,
    const int output_padding_w,
    const T multiplier
) {
    // Each thread handles one output spatial position for one output channel and batch
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    const int total_elements = batch_size * out_channels * out_height * out_width;

    if (idx >= total_elements) {
        return;
    }

    // Decompose index
    const int b = idx / (out_channels * out_height * out_width);
    const int remainder = idx % (out_channels * out_height * out_width);
    const int oc = remainder / (out_height * out_width);
    const int spatial_remainder = remainder % (out_height * out_width);
    const int oh = spatial_remainder / out_width;
    const int ow = spatial_remainder % out_width;

    T sum = 0.0;

    // Compute input window for this output position
    const int ih_start = oh * stride_h - padding_h;
    const int iw_start = ow * stride_w - padding_w;

    // Iterate over input channels
    for (int ic = 0; ic < in_channels; ic++) {
        // Iterate over kernel
        for (int kh = 0; kh < kernel_h; kh++) {
            for (int kw = 0; kw < kernel_w; kw++) {
                const int ih = ih_start + kh;
                const int iw = iw_start + kw;

                // Check bounds
                if (ih >= 0 && ih < in_height && iw >= 0 && iw < in_width) {
                    const int input_idx = ((b * in_channels + ic) * in_height + ih) * in_width + iw;
                    const int weight_idx = ((oc * in_channels + ic) * kernel_h + kh) * kernel_w + kw;

                    sum += input[input_idx] * weight[weight_idx];
                }
            }
        }
    }

    // Add bias
    sum += bias[oc];

    // Apply multiplier
    sum *= multiplier;

    // Store intermediate result
    output[idx] = sum;
}

template<typename T>
__global__ void global_average_pool_kernel(
    const T* input,
    T* output,
    const int batch_size,
    const int channels,
    const int height,
    const int width
) {
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    const int total_channels = batch_size * channels;

    if (idx >= total_channels) {
        return;
    }

    const int b = idx / channels;
    const int c = idx % channels;

    T sum = 0.0;

    // Sum over spatial dimensions
    for (int h = 0; h < height; h++) {
        for (int w = 0; w < width; w++) {
            const int input_idx = ((b * channels + c) * height + h) * width + w;
            sum += input[input_idx];
        }
    }

    // Average and store
    output[idx] = sum / static_cast<T>(height * width);
}

torch::Tensor fused_conv_transpose_pool_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    torch::IntArrayRef stride,
    torch::IntArrayRef padding,
    torch::IntArrayRef output_padding,
    double multiplier
) {
    // Get tensor dimensions
    const int batch_size = input.size(0);
    const int in_channels = input.size(1);
    const int in_height = input.size(2);
    const int in_width = input.size(3);

    const int out_channels = weight.size(0);
    const int kernel_h = weight.size(2);
    const int kernel_w = weight.size(3);

    // Calculate output dimensions for ConvTranspose2d
    const int out_height = (in_height - 1) * stride[0] - 2 * padding[0] + kernel_h + output_padding[0];
    const int out_width = (in_width - 1) * stride[1] - 2 * padding[1] + kernel_w + output_padding[1];

    // Create intermediate output tensor
    auto intermediate = torch::empty({batch_size, out_channels, out_height, out_width}, 
                                     input.options());

    // Launch fused kernel for ConvTranspose + Scalar Multiplication
    const int total_elements = batch_size * out_channels * out_height * out_width;
    const int threads_per_block = 256;
    const int num_blocks = (total_elements + threads_per_block - 1) / threads_per_block;

    AT_DISPATCH_FLOATING_TYPES(input.scalar_type(), "fused_conv_transpose_pool", ([&] {
        fused_conv_transpose_pool_kernel<scalar_t><<<num_blocks, threads_per_block>>>(
            input.data_ptr<scalar_t>(),
            weight.data_ptr<scalar_t>(),
            bias.data_ptr<scalar_t>(),
            intermediate.data_ptr<scalar_t>(),
            batch_size,
            in_channels,
            out_channels,
            in_height,
            in_width,
            out_height,
            out_width,
            kernel_h,
            kernel_w,
            stride[0],
            stride[1],
            padding[0],
            padding[1],
            output_padding[0],
            output_padding[1],
            static_cast<scalar_t>(multiplier)
        );
    }));

    cudaDeviceSynchronize();

    // First global average pooling
    auto pooled1 = torch::empty({batch_size, out_channels, 1, 1}, input.options());

    const int total_channels1 = batch_size * out_channels;
    const int num_blocks1 = (total_channels1 + threads_per_block - 1) / threads_per_block;

    AT_DISPATCH_FLOATING_TYPES(input.scalar_type(), "global_average_pool1", ([&] {
        global_average_pool_kernel<scalar_t><<<num_blocks1, threads_per_block>>>(
            intermediate.data_ptr<scalar_t>(),
            pooled1.data_ptr<scalar_t>(),
            batch_size,
            out_channels,
            out_height,
            out_width
        );
    }));

    cudaDeviceSynchronize();

    // Second global average pooling (input is already 1x1 spatial size)
    // This is just dividing by 1, so we can directly return pooled1
    return pooled1;
}
"""

fused_conv_transpose_pool_cpp_source = """
torch::Tensor fused_conv_transpose_pool_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    torch::IntArrayRef stride,
    torch::IntArrayRef padding,
    torch::IntArrayRef output_padding,
    double multiplier
);
"""

# Compile the inline CUDA code
fused_conv_transpose_pool = load_inline(
    name="fused_conv_transpose_pool",
    cpp_sources=fused_conv_transpose_pool_cpp_source,
    cuda_sources=fused_conv_transpose_pool_source,
    functions=["fused_conv_transpose_pool_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_ldflags=[],
    with_cuda=True
)

class ModelNew(nn.Module):
    """
    Optimized model with fused CUDA kernels for ConvTranspose2d + Scalar Multiplication + Global Average Pooling
    """
    def __init__(self, in_channels, out_channels, kernel_size, stride, padding, output_padding, multiplier):
        super(ModelNew, self).__init__()

        # Store parameters
        self.in_channels = in_channels
        self.out_channels = out_channels
        self.kernel_size = kernel_size if isinstance(kernel_size, tuple) else (kernel_size, kernel_size)
        self.stride = stride if isinstance(stride, tuple) else (stride, stride)
        self.padding = padding if isinstance(padding, tuple) else (padding, padding)
        self.output_padding = output_padding if isinstance(output_padding, tuple) else (output_padding, output_padding)
        self.multiplier = multiplier

        # Initialize weights and bias with the same initialization as nn.ConvTranspose2d
        self.weight = nn.Parameter(torch.empty(
            in_channels, out_channels, self.kernel_size[0], self.kernel_size[1]
        ))
        self.bias = nn.Parameter(torch.empty(out_channels))

        # Use the same initialization as nn.ConvTranspose2d
        nn.init.kaiming_uniform_(self.weight, a=0, mode='fan_in', nonlinearity='relu')
        if self.bias is not None:
            fan_in, _ = nn.init._calculate_fan_in_and_fan_out(self.weight)
            bound = 1 / math.sqrt(fan_in)
            nn.init.uniform_(self.bias, -bound, bound)

        # Store the custom CUDA operation
        self.fused_op = fused_conv_transpose_pool

    def forward(self, x):
        # Transpose weight to match ConvTranspose2d layout: (in_channels, out_channels, kH, kW) -> (out_channels, in_channels, kH, kW)
        weight_transposed = self.weight.permute(1, 0, 2, 3).contiguous()

        # Use the fused CUDA kernel for the entire operation
        return self.fused_op.fused_conv_transpose_pool_cuda(
            x,
            weight_transposed,
            self.bias,
            self.stride,
            self.padding,
            self.output_padding,
            self.multiplier
        )

